const sheetResp = $input.first().json;
const values = sheetResp.values || [];

const HUB_TO_PILAR = {
  'Salud': { slug: 'guia-salud-canina', titulo_seccion: 'salud canina' },
  'Alimentación': { slug: 'guia-alimentacion-perros', titulo_seccion: 'alimentación canina' },
  'Razas': { slug: 'guia-razas-perros', titulo_seccion: 'razas de perros' },
  'Comportamiento': { slug: 'guia-comportamiento-canino', titulo_seccion: 'comportamiento canino' }
};

const hubData = {};
const rows = values.slice(1);
for (const row of rows) {
  const keyword = (row[0] || '').trim();
  const estado = (row[1] || '').trim();
  const urlPost = (row[7] || '').trim();
  const hub = (row[17] || '').trim();

  if (estado !== 'Publicado' || !urlPost || !keyword || !hub) continue;

  const meta = HUB_TO_PILAR[hub];
  if (!meta) continue;

  if (!hubData[hub]) hubData[hub] = { hub, pilar_slug: meta.slug, titulo_seccion: meta.titulo_seccion, clusters: [] };
  hubData[hub].clusters.push({ keyword, url: urlPost });
}

const items = Object.values(hubData).map(d => ({ json: d }));
if (items.length === 0) throw new Error('No se encontraron clusters publicados con hub asignado');
return items;

const pilarArray = $input.item.json;
const pilar = Array.isArray(pilarArray) ? pilarArray[0] : pilarArray;
if (!pilar || !pilar.id) throw new Error('Pilar no encontrado en respuesta WP');

const hubCtx = $('Agrupar Clusters por Hub').itemMatching($itemIndex).json;

const pageId = pilar.id;
let contentRaw = (pilar.content && (pilar.content.raw || pilar.content.rendered)) || '';

const items = hubCtx.clusters.map(c => 
  '<li><a href="' + c.url + '">' + c.keyword + '</a></li>'
).join('');

const nuevaSeccion = '<section class="cluster-list" data-pillar="' + hubCtx.pilar_slug + '">' +
  '<h2>Más artículos sobre ' + hubCtx.titulo_seccion + '</h2>' +
  '<p>Nuestra biblioteca creciente de contenidos del hub. ' + hubCtx.clusters.length + ' artículo' + (hubCtx.clusters.length === 1 ? '' : 's') + ' disponible' + (hubCtx.clusters.length === 1 ? '' : 's') + '.</p>' +
  '<ul class="cluster-items">' + items + '</ul>' +
  '</section>';

contentRaw = contentRaw.replace(/<section class="cluster-list"[\s\S]*?<\/section>/g, '');

const scriptIdx = contentRaw.indexOf('<script type="application/ld+json">');
let newContent;
if (scriptIdx > -1) {
  newContent = contentRaw.slice(0, scriptIdx) + nuevaSeccion + contentRaw.slice(scriptIdx);
} else {
  newContent = contentRaw + nuevaSeccion;
}

return { json: {
  page_id: pageId,
  hub: hubCtx.hub,
  pilar_slug: hubCtx.pilar_slug,
  cluster_count: hubCtx.clusters.length,
  patch_body_json: JSON.stringify({ content: newContent })
}};

const items = $('Construir HTML Inyectado').all();
const lines = items.map(it => {
  const j = it.json;
  return '• ' + j.hub + ': ' + j.cluster_count + ' clusters → https://bigotescaninos.com/' + j.pilar_slug + '/';
});

const summary = '🔄 *Pilares actualizados* ✅\n\n' + lines.join('\n') + '\n\n_Cada pilar tiene la sección "Más artículos sobre..." actualizada con todos los clusters publicados._';

return [{ json: { summary } }];
